function BrowseProjects({ data, citiesProject, slug }) {
    const navigate = useNavigate()
    const { objectToQueryString } = useAuth()
    const cards = [
        { img: karachi, name: 'Karachi' },
        { img: islamabad, name: 'Islamabad' },
        { img: rawalpindi, name: 'Rawalpindi' },
        { img: lahore, name: 'Lahore' },
        { img: faislabad, name: 'Faisalabad' },
        { img: multan, name: 'Multan' },
    ]

    const [selectedCityCode, setSelectedCityCode] = useState(null);
    const touchStartRef = useRef({ x: 0, y: 0, time: 0 });

    const handleTouchStart = (e) => {
        const touch = e.touches[0];
        touchStartRef.current = {
            x: touch.clientX,
            y: touch.clientY,
            time: Date.now()
        };
    };

    const handleTouchEnd = (e, item) => {
        if (!e.changedTouches || !e.changedTouches[0]) return;
        
        const touch = e.changedTouches[0];
        const deltaX = Math.abs(touch.clientX - touchStartRef.current.x);
        const deltaY = Math.abs(touch.clientY - touchStartRef.current.y);
        const deltaTime = Date.now() - touchStartRef.current.time;
        
        // Only trigger if it's a tap (small movement and short duration), not a scroll
        if (deltaX < 10 && deltaY < 10 && deltaTime < 300) {
            e.preventDefault();
            handleCardSelect(item);
        }
    };

    const handleCardSelect = (item) => {
        setSelectedCityCode(item?.city_code);
        const queryString = objectToQueryString({ city_code: item?.city_code });
        const { img, ...safeItem } = item; // Remove non-serializable React element
        if(slug){
            navigate(`/project-listing/${slug}?${queryString}`, { state: safeItem });
        }
        else{
            navigate(`/project-listing/${"housing-societies"}?${queryString}`, { state: safeItem });
        }
    };

    // Filter only those cities that exist in citiesProject data
    const matchedCities = citiesProject
        ?.map(item => {
            const match = cards.find(card =>
                card.name.toLowerCase() === item?.city_name?.toLowerCase()
            );
            return match ? { ...item, ...match } : null;
        })
        .filter(Boolean); // remove nulls

    return (
        <div className='agency-by-city'>
            <div className="heading">{data || 'Browse Projects by City'}</div>
            <div className="city-box row" style={{ gap: '12px 0' }}>
                {matchedCities?.map((item, index) => (
                    <div key={index} className="col-xl-2 col-lg-3 col-md-4 col-sm-4 col-6 px-2">
                        <div
                            className={`city-card mx-1${selectedCityCode === item?.city_code ? ' selected-city-card' : ''}`}
                            onClick={() => handleCardSelect(item)}
                            onTouchStart={handleTouchStart}
                            onTouchEnd={(e) => handleTouchEnd(e, item)}
                        >
                            <div className="img">
                                {item?.img}
                            </div>
                            <div className="name">{item.city_name}</div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default BrowseProjects;
